Resource: module.storage.aws_s3_bucket_lifecycle_configuration.documents
File: /iac/modules/storage/main.tf: 42-63
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-general-policies/bc-aws-300

		42 | resource "aws_s3_bucket_lifecycle_configuration" "documents" {
		43 |   bucket = aws_s3_bucket.documents.id
		44 | 
		45 |   rule {
		46 |     id     = "archiving-old-contracts"
		47 |     status = "Enabled"
		48 | 
		49 |     filter {}
		50 | 
		51 |     # A los 90 días el contrato pasa a almacenamiento de acceso poco frecuente (Standard-IA)
		52 |     transition {
		53 |       days          = 90
		54 |       storage_class = "STANDARD_IA"
		55 |     }
		56 | 
		57 |     # A los 180 días se archiva de forma masiva en Glacier para cumplimiento legal histórico
		58 |     transition {
		59 |       days          = 180
		60 |       storage_class = "GLACIER"
		61 |     }
		62 |   }
		63 | }

